// App.jsx — Root component with routing
// Changed: /topic/:topicName now renders LearnPage (new AI-powered learn page)
//          TopicDetail (old page) is kept for backward compat but no longer routed
import React from "react";
import { BrowserRouter as Router, Routes, Route } from "react-router-dom";
import Navbar     from "./components/Navbar";
import Home       from "./pages/Home";
import LearnPage  from "./pages/LearnPage";   // ← new
import Practice   from "./pages/Practice";
import Quiz       from "./pages/Quiz";
import Progress   from "./pages/Progress";

export default function App() {
  return (
    <Router>
      <div className="min-h-screen bg-bg text-white">
        <Navbar />
        <Routes>
          <Route path="/"                 element={<Home />} />
          <Route path="/topic/:topicName" element={<LearnPage />} />  {/* ← new */}
          <Route path="/practice"         element={<Practice />} />
          <Route path="/quiz"             element={<Quiz />} />
          <Route path="/progress"         element={<Progress />} />
        </Routes>
      </div>
    </Router>
  );
}
